'use strict';

// Semantic-version precedence sorting. See docs/registry.md for the contract
// and docs/conventions.md for the precedence rules (numeric core fields,
// pre-release lower than release, build metadata ignored for precedence).
//
// Returns the input version strings sorted ascending by SemVer precedence,
// each original string preserved verbatim (build metadata is not stripped),
// without mutating the input array.

function parseVersion(v) {
  const buildIdx = v.indexOf('+');
  const withoutBuild = buildIdx === -1 ? v : v.slice(0, buildIdx);

  const preIdx = withoutBuild.indexOf('-');
  const corePart = preIdx === -1 ? withoutBuild : withoutBuild.slice(0, preIdx);
  const prePart = preIdx === -1 ? null : withoutBuild.slice(preIdx + 1);

  const parts = corePart.split('.');
  return {
    major: Number(parts[0]),
    minor: Number(parts[1]),
    patch: Number(parts[2]),
    preRelease: prePart !== null ? prePart.split('.') : null,
  };
}

function comparePreRelease(a, b) {
  if (a === null && b === null) return 0;
  if (a === null) return 1;   // release > pre-release
  if (b === null) return -1;  // pre-release < release

  const len = Math.max(a.length, b.length);
  for (let i = 0; i < len; i++) {
    if (i >= a.length) return -1; // fewer fields = lower precedence
    if (i >= b.length) return 1;

    const aId = a[i];
    const bId = b[i];
    const aNum = /^\d+$/.test(aId);
    const bNum = /^\d+$/.test(bId);

    if (aNum && bNum) {
      const diff = Number(aId) - Number(bId);
      if (diff !== 0) return diff;
    } else {
      if (aId < bId) return -1;
      if (aId > bId) return 1;
    }
  }
  return 0;
}

function compareVersions(a, b) {
  const pa = parseVersion(a);
  const pb = parseVersion(b);

  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;

  return comparePreRelease(pa.preRelease, pb.preRelease);
}

function sortVersions(versions) {
  return versions.slice().sort(compareVersions);
}

module.exports = { sortVersions };

